"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[693],{7825:(e,n,r)=>{r.r(n),r.d(n,{assets:()=>d,contentTitle:()=>a,default:()=>m,frontMatter:()=>o,metadata:()=>t,toc:()=>c});const t=JSON.parse('{"id":"project/2026/andrei.dascalescu/index","title":"AWARE-GUIN","description":"An interactive companion robot developed on STM32 using Async Rust (Embassy).","source":"@site/versioned_docs/version-fils_en/project/2026/andrei.dascalescu/index.md","sourceDirName":"project/2026/andrei.dascalescu","slug":"/project/2026/andrei.dascalescu/","permalink":"/docs/fils_en/project/2026/andrei.dascalescu/","draft":false,"unlisted":false,"editUrl":"https://www.github.com/upb-pmrust/website/edit/main/website/versioned_docs/version-fils_en/project/2026/andrei.dascalescu/index.md","tags":[],"version":"fils_en","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Tricopter Drone","permalink":"/docs/fils_en/project/2026/andrei.codita/"},"next":{"title":"PlantGuard Node","permalink":"/docs/fils_en/project/2026/andrei.florea2012/"}}');var s=r(74848),i=r(28453);const o={},a="AWARE-GUIN",d={},c=[{value:"Description",id:"description",level:2},{value:"Motivation",id:"motivation",level:2},{value:"Architecture",id:"architecture",level:2}];function l(e){const n={a:"a",admonition:"admonition",br:"br",code:"code",h1:"h1",h2:"h2",header:"header",mdxAdmonitionTitle:"mdxAdmonitionTitle",p:"p",pre:"pre",strong:"strong",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"aware-guin",children:"AWARE-GUIN"})}),"\n",(0,s.jsx)(n.p,{children:"An interactive companion robot developed on STM32 using Async Rust (Embassy)."}),"\n",(0,s.jsxs)(n.admonition,{type:"info",children:[(0,s.jsx)(n.mdxAdmonitionTitle,{}),(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Author"}),": [DASCALESCU ANDREI] ",(0,s.jsx)(n.br,{}),"\n",(0,s.jsx)(n.strong,{children:"GitHub Project Link"}),": [",(0,s.jsx)(n.a,{href:"https://github.com/UPB-PMRust-Students/fils-project-2026-yvcc28s62s-cmd",children:"https://github.com/UPB-PMRust-Students/fils-project-2026-yvcc28s62s-cmd"}),"]"]})]}),"\n",(0,s.jsx)(n.h2,{id:"description",children:"Description"}),"\n",(0,s.jsxs)(n.p,{children:['AWARE-GUIN is an intelligent desktop companion designed to react to its environment through visual expressions and light feedback. The "brain" of the project is a state-of-the-art STM32U5 microcontroller, programmed exclusively in Rust. The system runs on the ',(0,s.jsx)(n.code,{children:"Embassy"})," asynchronous framework, concurrently managing an SPI display for the face/UI, a smart LED ring (NeoPixel) for expressing moods, and I2C sensors for gathering environmental data."]}),"\n",(0,s.jsx)(n.h2,{id:"motivation",children:"Motivation"}),"\n",(0,s.jsx)(n.p,{children:"The primary motivation for this project was to transition from classic, sequential embedded programming (C/C++) to the modern, memory-safe, and asynchronous ecosystem provided by Rust. AWARE-GUIN served as the perfect sandbox to explore advanced concepts such as cooperative multitasking on bare-metal hardware, direct hardware abstraction layer (HAL) manipulation, and real-world debugging of communication protocols (high-speed SPI and I2C)."}),"\n",(0,s.jsx)(n.h2,{id:"architecture",children:"Architecture"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-text",children:"               [ DATA & TIME ]                          [ VISUAL DISPLAY ]\r\n                .-------------.                         .---------------.\r\n                |  RTC Module |                         | Displays (SPI)|\r\n                |  Real-Time  |                         | Multiple TFT/ |\r\n                '-------------'                         | OLED          |\r\n                      ^                                 '---------------'\r\n                      | (I2C)                                   ^\r\n                      v                                         | (SPI 1 & 2)\r\n.-------------.                 .-------------------.           v     .-------------.\r\n| HC-05 (UART)|                 |                   |                 | WS2812 Ring |\r\n|  Bluetooth  |<---(RX/TX)-----\x3e|  AWARE-GUIN Core  |<----(SPI @3MHz)>|  RGB LEDs   |\r\n| Comm Module |                 | (STM32 Nucleo-U5) |                 | Expressions |\r\n'-------------'                 |                   |                 '-------------'\r\n                                '-------------------'\r\n                      ^                                         ^\r\n                      | (I2C / ADC)                             | (PWM Signal)\r\n                      v                                         v\r\n                .-------------.                         .---------------.\r\n                |  Multiple   |                         | Servo Motors  |\r\n                |   Sensors   |                         |  Mechanical   |\r\n                |  (Env/IR)   |                         |  Actuation    |\r\n                '-------------'                         '---------------'\r\n                [ PERCEPTION ]                             [ ACTION ]\r\n\r\n## Log\r\n### Week 5 - 11 May\r\n* Researched STM32U5 documentation and set up the Rust embedded toolchain (`probe-rs`, `defmt`).\r\n* Configured the Embassy async framework and successfully ran an async Blinky task.\r\n* Conducted initial SPI communication tests and hardware initialization for the TFT display.\r\n\r\n### Week 12 - 18 May\r\n* Performed advanced hardware debugging on the SPI bus (resolving \"white screen\" issues and adjusting clock polarity - MODE_0 / MODE_3).\r\n* Successfully integrated the `mipidsi` and `embedded-graphics` crates.\r\n* Controlled the WS2812 LED ring via SPI using the `smart-leds` crate and generated non-blocking animations.\r\n\r\n### Week 19 - 25 May\r\n* Wired and tested the I2C environmental sensors.\r\n* Unified all components (Display, LEDs, Sensors) into a single asynchronous `main` execution loop.\r\n* Optimized the codebase for the `release` profile and finalized the hardware schematics.\r\n\r\n## Hardware\r\nThe system relies on an STM32 Nucleo board as the central processing unit, expanded with peripheral modules connected directly to the exposed header pins.\r\n\r\n### Schematics\r\n![KiCAD schematic](./Circuit.svg)\r\n\r\n### Bill of Materials\r\n| Device | Usage | Price |\r\n|--------|--------|-------|\r\n| [STM32U545RE Nucleo](https://www.st.com/en/evaluation-tools/nucleo-u545re-q.html) | The main microcontroller running the Rust logic | [~110 RON](#) |\r\n| [SPI TFT Display (ST7789/ILI9341)](https://www.optimusdigital.ro/) | The screen used to render the robot's face | [~40 RON](#) |\r\n| [7-LED WS2812 Ring](https://www.optimusdigital.ro/) | Luminous feedback / Mood lighting | [~15 RON](#) |\r\n| [I2C Sensor Module](https://www.optimusdigital.ro/) | Gathering environmental data | [~20 RON](#) |\r\n| Dupont Wires & Breadboard | Physical connections between components | [~25 RON](#) |\r\n\r\n## Software\r\n| Library | Description | Usage |\r\n|---------|-------------|-------|\r\n| [embassy-stm32](https://github.com/embassy-rs/embassy) | Async HAL for the STM32 family | Configuring system clocks, I2C, SPI, and GPIO pins. |\r\n| [mipidsi](https://github.com/almindor/mipidsi) | Universal display driver | Low-level communication and hardware initialization for the screen controller. |\r\n| [embedded-graphics](https://github.com/embedded-graphics/embedded-graphics) | 2D graphics library | Hardware-agnostic rendering of text, geometries, and expressions on the screen. |\r\n| [ws2812-spi](https://github.com/smart-leds-rs/ws2812-spi) | WS2812 driver | Driving the smart LED ring directly through SPI pins. |\r\n| [defmt](https://defmt.ferrous-systems.com/) | Ultra-fast logging framework | Printing system logs (Info, Debug, Error) via the debugging probe interface. |\r\n\r\n## Links\r\n1. [Embassy Book - Official Documentation for Rust Async Embedded](https://embassy.dev/book/dev/index.html)\r\n2. [Embedded Graphics - Visual guide and examples](https://docs.rs/embedded-graphics/latest/embedded_graphics/)\r\n3. [Rust on STM32 - The Embedded Rust Book](https://docs.rust-embedded.org/book/)\n"})})]})}function m(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},28453:(e,n,r)=>{r.d(n,{R:()=>o,x:()=>a});var t=r(96540);const s={},i=t.createContext(s);function o(e){const n=t.useContext(i);return t.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:o(e.components),t.createElement(i.Provider,{value:n},e.children)}}}]);